arguments.command:
# Check full symtab from debuginfo for these addresses
DEBUGINFO=/tmp/libmonosgen-debuginfo

for addr in 0x2f4b20 0x2f4c84; do
  echo "--- Address $addr ---"
  readelf -s $DEBUGINFO 2>/dev/null | awk -v a="$addr" '
    BEGIN { target = strtonum(a); best_name = "??"; best_addr = 0 }
    /FUNC/ {
      sym_addr = strtonum("0x" $2)
      if (sym_addr <= target && sym_addr > best_addr) {
        best_addr = sym_addr
        best_size = strtonum($3 + 0)
        best_name = $NF
      }
    }
    END { printf "  %s+0x%x (sym_start: 0x%x, size: %d)\n", best_name, target - best_addr, best_addr, best_size }
  '
done

