arguments.command:
# Check the original .so (with actual code) for section boundaries
readelf -SW /tmp/libmonosgen-debug.so 2>/dev/null | grep -E '^\s+\[' | awk '{
  name=$2; type=$3; addr=$4; size=$6
  if (type == "PROGBITS" || type == "NOBITS") {
    a = strtonum("0x"addr)
    s = strtonum("0x"size)
    if (a > 0) printf "  %-20s 0x%06x - 0x%06x (%s)\n", name, a, a+s, type
  }
}' | sort -k2

