arguments.command:
# For SGen worker, find nearest dynsym FUNC entries to provide context
readelf --dyn-syms /tmp/libmonosgen-debug.so 2>/dev/null | awk '
/FUNC.*GLOBAL/ {
  addr = strtonum("0x" $2)
  size = strtonum($3)
  name = $NF
  # Check if 0x2f4b20 or 0x2f4c84 fall in range
  if (addr <= 0x2f4c84 && addr + size > 0x2f4b20) {
    printf "Contains both: %s @ 0x%x (size %d)\n", name, addr, size
  }
  # Show functions in the vicinity
  if (addr >= 0x2f3000 && addr <= 0x2f6000) {
    printf "Nearby: %s @ 0x%x (size %d)\n", name, addr, size
  }
}'

echo ""
echo "=== Summary: nearest exported function to 0x2f4b20 ==="
readelf --dyn-syms /tmp/libmonosgen-debug.so 2>/dev/null | awk '
/FUNC/ {
  addr = strtonum("0x" $2)
  name = $NF
  if (addr <= 0x2f4b20) {
    best_addr = addr
    best_name = name
  }
}
END { printf "%s @ 0x%x (offset: +0x%x)\n", best_name, best_addr, 0x2f4b20 - best_addr }'

